"use client"

import { Edit, Eye, EyeOff, ImageIcon, Map, MapPin, Plus, RefreshCw, Save, Upload } from "lucide-react"
import { useEffect, useMemo, useRef, useState } from "react"
import { toast } from "sonner"
import { AdminFrame } from "@/components/dg/admin-frame"
import { authHeaders, request, resolveMediaURL, splitTags } from "@/components/dg/api"
import { Button } from "@/components/ui/button"
import { Card } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Switch } from "@/components/ui/switch"
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs"
import { Textarea } from "@/components/ui/textarea"

type Spot = {
  id?: number
  name: string
  name_en: string | null
  description: string | null
  description_en: string | null
  tags: string[]
  location: { lat?: number; lng?: number; latitude?: number; longitude?: number } | null
  visit_duration_min: number
  image_url: string | null
  sort_order: number
  is_active: boolean
}

type Route = {
  id: number
  name: string
  name_en: string | null
  description: string | null
  tags: string[]
  spot_ids: number[]
  sort_order: number
  is_active: boolean
}

const emptySpot: Spot = {
  name: "",
  name_en: null,
  description: null,
  description_en: null,
  tags: [],
  location: null,
  visit_duration_min: 30,
  image_url: null,
  sort_order: 0,
  is_active: true,
}

function normalizeSpot(value: any): Spot {
  return {
    ...emptySpot,
    ...value,
    tags: Array.isArray(value?.tags) ? value.tags : [],
    location: value?.location || null,
    image_url: value?.image_url || null,
  }
}

function locationText(spot: Spot) {
  const lat = spot.location?.lat ?? spot.location?.latitude
  const lng = spot.location?.lng ?? spot.location?.longitude
  if (!Number.isFinite(Number(lat)) || !Number.isFinite(Number(lng))) return "暂无坐标"
  return `${Number(lat).toFixed(5)}, ${Number(lng).toFixed(5)}`
}

function SpotImage({ spot, className }: { spot: Spot; className: string }) {
  const src = spot.image_url ? resolveMediaURL(spot.image_url) : ""
  const [failed, setFailed] = useState(false)

  useEffect(() => {
    setFailed(false)
  }, [src])

  if (!src || failed) {
    return (
      <div className={`${className} grid place-items-center bg-muted text-muted-foreground`}>
        <ImageIcon className="h-5 w-5" />
      </div>
    )
  }

  return (
    <img
      className={className}
      src={src}
      alt={spot.name}
      loading="lazy"
      onError={() => setFailed(true)}
    />
  )
}

function SpotList({ onSelect, selectedId, spots }: { onSelect: (spot: Spot) => void; selectedId?: number; spots: Spot[] }) {
  if (!spots.length) {
    return (
      <Card className="grid min-h-48 place-items-center border-dashed p-6 text-center text-sm text-muted-foreground">
        暂无景点数据
      </Card>
    )
  }

  return (
    <div className="space-y-3">
      {spots.map((spot) => (
        <button
          key={spot.id}
          type="button"
          onClick={() => onSelect(spot)}
          className={`group flex w-full items-stretch gap-4 rounded-[8px] border bg-card p-3 text-left shadow-sm transition hover:border-primary/30 hover:shadow-md ${
            selectedId === spot.id ? "border-primary/50 ring-2 ring-primary/10" : "border-border"
          }`}
        >
          <SpotImage spot={spot} className="h-24 w-32 shrink-0 rounded-[8px] object-cover" />
          <div className="min-w-0 flex-1 py-1">
            <div className="flex items-start justify-between gap-3">
              <div className="min-w-0">
                <h3 className="truncate text-base font-semibold text-foreground">{spot.name || "未命名景点"}</h3>
                {spot.name_en ? <p className="truncate text-xs text-muted-foreground">{spot.name_en}</p> : null}
              </div>
              <span className={`inline-flex shrink-0 items-center rounded-full px-2 py-1 text-xs ${spot.is_active ? "bg-green-100 text-green-700" : "bg-muted text-muted-foreground"}`}>
                {spot.is_active ? <Eye className="mr-1 h-3 w-3" /> : <EyeOff className="mr-1 h-3 w-3" />}
                {spot.is_active ? "上线" : "下线"}
              </span>
            </div>
            {spot.description ? <p className="mt-2 line-clamp-2 text-sm leading-6 text-muted-foreground">{spot.description}</p> : null}
            <div className="mt-3 flex flex-wrap items-center gap-2">
              <span className="inline-flex items-center gap-1 text-xs text-muted-foreground">
                <MapPin className="h-3.5 w-3.5" />
                {locationText(spot)}
              </span>
              {spot.tags.slice(0, 3).map((tag) => (
                <span key={tag} className="rounded-full bg-primary/10 px-2 py-0.5 text-xs text-primary">
                  {tag}
                </span>
              ))}
            </div>
          </div>
          <div className="flex items-center pr-1 text-muted-foreground transition group-hover:text-primary">
            <Edit className="h-4 w-4" />
          </div>
        </button>
      ))}
    </div>
  )
}

function SpotEditor({ spot: initial, onSaved }: { spot: Spot | null; onSaved: (spot?: Spot) => void }) {
  const [spot, setSpot] = useState<Spot>(normalizeSpot(initial || emptySpot))
  const [saving, setSaving] = useState(false)
  const [tagInput, setTagInput] = useState("")
  const [imagePreview, setImagePreview] = useState("")
  const [imageLoadFailed, setImageLoadFailed] = useState(false)
  const fileInputRef = useRef<HTMLInputElement>(null)

  useEffect(() => {
    const next = normalizeSpot(initial || emptySpot)
    setSpot(next)
    setTagInput("")
    setImageLoadFailed(false)
    setImagePreview(next.image_url ? resolveMediaURL(next.image_url) : "")
    if (fileInputRef.current) fileInputRef.current.value = ""
  }, [initial])

  const selectedFile = fileInputRef.current?.files?.[0]

  function update<K extends keyof Spot>(key: K, value: Spot[K]) {
    setSpot((current) => ({ ...current, [key]: value }))
  }

  function updateLocation(key: "lat" | "lng", value: string) {
    const number = value === "" ? undefined : Number(value)
    setSpot((current) => ({
      ...current,
      location: {
        ...(current.location || {}),
        [key]: Number.isFinite(number) ? number : undefined,
      },
    }))
  }

  function handleFileChange(event: React.ChangeEvent<HTMLInputElement>) {
    const file = event.target.files?.[0]
    if (!file) return
    if (file.size > 10 * 1024 * 1024) {
      toast.error("图片不能超过 10MB")
      event.target.value = ""
      return
    }
    setImageLoadFailed(false)
    setImagePreview(URL.createObjectURL(file))
  }

  async function saveSpot() {
    if (!spot.name.trim()) {
      toast.error("请填写景点名称")
      return
    }

    setSaving(true)
    try {
      const payload = {
        name: spot.name.trim(),
        name_en: spot.name_en || null,
        description: spot.description || null,
        description_en: spot.description_en || null,
        tags: spot.tags,
        location: spot.location,
        visit_duration_min: Number(spot.visit_duration_min || 0),
        sort_order: Number(spot.sort_order || 0),
        is_active: Boolean(spot.is_active),
      }

      let saved = initial?.id
        ? await request<Spot>(`/api/admin/spots/${initial.id}`, {
            method: "PUT",
            headers: authHeaders({ "Content-Type": "application/json" }),
            body: JSON.stringify(payload),
          })
        : await request<Spot>("/api/admin/spots", {
            method: "POST",
            headers: authHeaders({ "Content-Type": "application/json" }),
            body: JSON.stringify(payload),
          })

      const file = fileInputRef.current?.files?.[0]
      if (file && saved.id) {
        const form = new FormData()
        form.append("file", file)
        const imageResult = await request<{ image_url: string }>(`/api/admin/spots/${saved.id}/image`, {
          method: "POST",
          headers: authHeaders(),
          body: form,
        })
        saved = { ...saved, image_url: imageResult.image_url }
        setImagePreview(resolveMediaURL(imageResult.image_url))
        if (fileInputRef.current) fileInputRef.current.value = ""
      }

      setSpot(normalizeSpot(saved))
      toast.success(initial?.id ? "景点已更新" : "景点已新增")
      onSaved(normalizeSpot(saved))
    } catch (error: any) {
      toast.error(error?.message || "保存失败")
    } finally {
      setSaving(false)
    }
  }

  const lat = spot.location?.lat ?? spot.location?.latitude ?? ""
  const lng = spot.location?.lng ?? spot.location?.longitude ?? ""

  return (
    <div className="space-y-5">
      <div className="grid gap-4 md:grid-cols-2">
        <div className="space-y-2">
          <Label>景点名称 <span className="text-destructive">*</span></Label>
          <Input value={spot.name} onChange={(event) => update("name", event.target.value)} placeholder="例如：灵山大佛" />
        </div>
        <div className="space-y-2">
          <Label>英文名称</Label>
          <Input value={spot.name_en || ""} onChange={(event) => update("name_en", event.target.value || null)} placeholder="Lingshan Grand Buddha" />
        </div>
      </div>

      <div className="grid gap-4 md:grid-cols-4">
        <div className="space-y-2">
          <Label>游览时长</Label>
          <Input type="number" min={0} value={spot.visit_duration_min} onChange={(event) => update("visit_duration_min", Number(event.target.value))} />
        </div>
        <div className="space-y-2">
          <Label>排序</Label>
          <Input type="number" value={spot.sort_order} onChange={(event) => update("sort_order", Number(event.target.value))} />
        </div>
        <div className="space-y-2">
          <Label>纬度</Label>
          <Input type="number" value={lat} onChange={(event) => updateLocation("lat", event.target.value)} placeholder="31.4231" />
        </div>
        <div className="space-y-2">
          <Label>经度</Label>
          <Input type="number" value={lng} onChange={(event) => updateLocation("lng", event.target.value)} placeholder="120.0955" />
        </div>
      </div>

      <div className="space-y-2">
        <Label>标签</Label>
        <div className="flex gap-2">
          <Input
            value={tagInput}
            onChange={(event) => setTagInput(event.target.value)}
            onKeyDown={(event) => {
              if (event.key !== "Enter") return
              event.preventDefault()
              const next = Array.from(new Set([...spot.tags, ...splitTags(tagInput)]))
              update("tags", next)
              setTagInput("")
            }}
            placeholder="历史文化, 摄影打卡"
          />
          <Button
            type="button"
            variant="outline"
            onClick={() => {
              const next = Array.from(new Set([...spot.tags, ...splitTags(tagInput)]))
              update("tags", next)
              setTagInput("")
            }}
          >
            添加
          </Button>
        </div>
        <div className="flex min-h-8 flex-wrap gap-2">
          {spot.tags.map((tag) => (
            <button
              key={tag}
              type="button"
              onClick={() => update("tags", spot.tags.filter((item) => item !== tag))}
              className="rounded-full bg-primary/10 px-2.5 py-1 text-xs text-primary transition hover:bg-destructive/10 hover:text-destructive"
            >
              {tag} ×
            </button>
          ))}
        </div>
      </div>

      <div className="grid gap-5 lg:grid-cols-[320px_minmax(0,1fr)]">
        <div className="space-y-2">
          <Label>景点图片</Label>
          <div className="rounded-[8px] border bg-muted/20 p-3">
            {imagePreview && !imageLoadFailed ? (
              <img
                src={imagePreview}
                alt="景点图片预览"
                className="h-48 w-full rounded-[8px] object-cover"
                onError={() => setImageLoadFailed(true)}
              />
            ) : (
              <div className="grid h-48 place-items-center rounded-[8px] bg-background text-sm text-muted-foreground">
                暂无图片预览
              </div>
            )}
            <input ref={fileInputRef} type="file" accept=".jpg,.jpeg,.png,.gif,.webp,image/*" onChange={handleFileChange} className="hidden" />
            <Button type="button" variant="outline" className="mt-3 w-full" onClick={() => fileInputRef.current?.click()}>
              <Upload className="h-4 w-4" />
              {selectedFile || spot.image_url ? "更换图片" : "选择图片"}
            </Button>
            <p className="mt-2 text-center text-xs text-muted-foreground">支持 jpg、png、gif、webp，最大 10MB</p>
          </div>
        </div>

        <div className="space-y-4">
          <div className="space-y-2">
            <Label>景点简介</Label>
            <Textarea value={spot.description || ""} onChange={(event) => update("description", event.target.value || null)} rows={6} placeholder="介绍景点特色、文化背景、推荐体验等内容" />
          </div>
          <div className="space-y-2">
            <Label>英文简介</Label>
            <Textarea value={spot.description_en || ""} onChange={(event) => update("description_en", event.target.value || null)} rows={4} placeholder="English introduction" />
          </div>
          <div className="flex items-center justify-between rounded-[8px] border px-4 py-3">
            <div>
              <Label>上线状态</Label>
              <p className="text-xs text-muted-foreground">下线后游客端不会优先展示该景点</p>
            </div>
            <Switch checked={spot.is_active} onCheckedChange={(value) => update("is_active", value)} />
          </div>
        </div>
      </div>

      <div className="flex justify-end gap-3 border-t pt-4">
        <Button type="button" variant="outline" onClick={() => {
          const next = normalizeSpot(initial || emptySpot)
          setSpot(next)
          setImagePreview(next.image_url ? resolveMediaURL(next.image_url) : "")
          setImageLoadFailed(false)
          if (fileInputRef.current) fileInputRef.current.value = ""
        }}>
          重置
        </Button>
        <Button type="button" onClick={saveSpot} disabled={saving || !spot.name.trim()}>
          {saving ? <RefreshCw className="h-4 w-4 animate-spin" /> : <Save className="h-4 w-4" />}
          {saving ? "保存中" : "保存景点"}
        </Button>
      </div>
    </div>
  )
}

function RouteList({ routes }: { routes: Route[] }) {
  if (!routes.length) {
    return <Card className="grid min-h-48 place-items-center border-dashed p-6 text-sm text-muted-foreground">暂无路线数据</Card>
  }

  return (
    <div className="space-y-3">
      {routes.map((route) => (
        <Card key={route.id} className="rounded-[8px] p-4 shadow-sm">
          <div className="flex items-start justify-between gap-4">
            <div className="min-w-0 flex-1">
              <h3 className="truncate font-semibold">{route.name}</h3>
              {route.description ? <p className="mt-1 line-clamp-2 text-sm text-muted-foreground">{route.description}</p> : null}
              <div className="mt-3 flex flex-wrap gap-2">
                {route.tags.map((tag) => <span key={tag} className="rounded-full bg-primary/10 px-2 py-0.5 text-xs text-primary">{tag}</span>)}
              </div>
            </div>
            <span className={`rounded-full px-2 py-1 text-xs ${route.is_active ? "bg-green-100 text-green-700" : "bg-muted text-muted-foreground"}`}>
              {route.is_active ? "上线" : "下线"}
            </span>
          </div>
        </Card>
      ))}
    </div>
  )
}

export function ScenicContent() {
  const [selected, setSelected] = useState<Spot | null>(null)
  const [spots, setSpots] = useState<Spot[]>([])
  const [routes, setRoutes] = useState<Route[]>([])
  const [loading, setLoading] = useState(true)

  const selectedId = selected?.id

  async function loadData(nextSelectedId = selectedId) {
    setLoading(true)
    try {
      const [spotsData, routesData] = await Promise.all([
        request<Spot[]>("/api/admin/spots", { headers: authHeaders() }),
        request<Route[]>("/api/admin/routes", { headers: authHeaders() }),
      ])
      const normalizedSpots = (Array.isArray(spotsData) ? spotsData : []).map(normalizeSpot)
      setSpots(normalizedSpots)
      setRoutes(Array.isArray(routesData) ? routesData : [])
      if (nextSelectedId) {
        setSelected(normalizedSpots.find((item) => item.id === nextSelectedId) || normalizedSpots[0] || null)
      } else if (!selected) {
        setSelected(normalizedSpots[0] || null)
      }
    } catch (error: any) {
      toast.error(error?.message || "加载失败")
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    loadData()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  const sortedSpots = useMemo(
    () => [...spots].sort((a, b) => Number(a.sort_order || 0) - Number(b.sort_order || 0) || String(a.name).localeCompare(String(b.name), "zh-CN")),
    [spots],
  )

  return (
    <AdminFrame
      title="景区管理"
      description="管理景点图片、基础信息、坐标和游览路线数据。"
      actions={
        <div className="flex flex-wrap gap-2">
          <Button type="button" onClick={() => setSelected(null)}>
            <Plus className="h-4 w-4" />
            新增景点
          </Button>
          <Button type="button" variant="outline" onClick={() => loadData()} disabled={loading}>
            <RefreshCw className={`h-4 w-4 ${loading ? "animate-spin" : ""}`} />
            刷新
          </Button>
        </div>
      }
    >
      {loading ? (
        <div className="grid min-h-80 place-items-center text-muted-foreground">加载中...</div>
      ) : (
        <div className="grid gap-6 xl:grid-cols-[minmax(0,0.95fr)_minmax(520px,1.05fr)]">
          <Tabs defaultValue="spots" className="min-w-0">
            <TabsList className="mb-4">
              <TabsTrigger value="spots"><MapPin className="mr-2 h-4 w-4" />景点列表</TabsTrigger>
              <TabsTrigger value="routes"><Map className="mr-2 h-4 w-4" />路线列表</TabsTrigger>
            </TabsList>
            <TabsContent value="spots" className="mt-0">
              <SpotList spots={sortedSpots} selectedId={selected?.id} onSelect={setSelected} />
            </TabsContent>
            <TabsContent value="routes" className="mt-0">
              <RouteList routes={routes} />
            </TabsContent>
          </Tabs>

          <Card className="rounded-[8px] p-5 shadow-sm">
            <div className="mb-5 flex items-center justify-between gap-3">
              <div>
                <h2 className="text-lg font-semibold">{selected?.id ? "编辑景点" : "新增景点"}</h2>
                <p className="text-sm text-muted-foreground">保存基础信息后，如选择了图片会自动上传并回显。</p>
              </div>
              {selected?.id ? <span className="rounded-full bg-muted px-3 py-1 text-xs text-muted-foreground">ID {selected.id}</span> : null}
            </div>
            <SpotEditor
              spot={selected}
              onSaved={(saved) => {
                if (saved) setSelected(saved)
                loadData(saved?.id)
              }}
            />
          </Card>
        </div>
      )}
    </AdminFrame>
  )
}
